// ============================================================================
// HELPER: GET BRAND FROM HEADPHONE NAME
// ============================================================================
function getBrand(name) {
  const lower = name.toLowerCase();
  if (lower.includes("steelseries") || lower.includes("arctis") || lower.includes("nova pro")) return "SteelSeries";
  if (lower.includes("hyperx") || (lower.includes("cloud") && !lower.includes("logitech"))) return "HyperX";
  if (lower.includes("razer") || lower.includes("blackshark") || lower.includes("barracuda") || lower.includes("kraken")) return "Razer";
  if (lower.includes("logitech") || lower.includes("g pro") || lower.includes("gpro")) return "Logitech";
  if (lower.includes("corsair")) return "Corsair";
  if (lower.includes("beyerdynamic")) return "beyerdynamic";
  if (lower.includes("sennheiser")) return "Sennheiser";
  if (lower.includes("astro") || lower.includes("a50") || lower.includes("a40")) return "Astro";
  if (lower.includes("sony") || lower.includes("inzone")) return "Sony";
  if (lower.includes("jbl")) return "JBL";
  if (lower.includes("asus") || lower.includes("rog")) return "ASUS ROG";
  if (lower.includes("audio-technica")) return "Audio-Technica";
  if (lower.includes("turtle beach")) return "Turtle Beach";
  if (lower.includes("apple")) return "Apple";
  if (lower.includes("blacklyte") || lower.includes("kraken pro")) return "Blacklyte";
  if (lower.includes("nova esports")) return "NOVA";
  const match = name.match(/^([A-Z][A-Za-z0-9\s&\-\.]+?)[\s\-]/);
  return match ? match[1].trim() : "Other";
}

// ============================================================================
// HELPER: DETECT TYPE (Wireless/Wired)
// ============================================================================
function getType(name) {
  const lower = name.toLowerCase();
  if (lower.includes("wireless")) return "Wireless";
  if (lower.includes("wired")) return "Wired";
  if (lower.includes("pro wireless") || lower.includes("flight")) return "Wireless";
  return "Wired";
}

// ============================================================================
// HELPER: DETECT STYLE (Over-Ear/In-Ear)
// ============================================================================
function getStyle(name) {
  const lower = name.toLowerCase();
  if (lower.includes("earbuds") || lower.includes("buds") || lower.includes("in-ear")) return "In-Ear";
  return "Over-Ear";
}

// ============================================================================
// HELPER: ESTIMATE PRICE
// ============================================================================
function estimatePrice(name, brand) {
  const lower = name.toLowerCase();

  // Premium models
  if (lower.includes("v3 pro")) return 199;
  if (lower.includes("v2 pro")) return 179;
  if (lower.includes("nova pro")) return 349;
  if (lower.includes("pro x 2")) return 229;
  if (lower.includes("inzone")) return 219;
  if (lower.includes("a50")) return 299;
  if (lower.includes("a40")) return 199;
  if (lower.includes("dt 1990")) return 599;
  if (lower.includes("dt 990")) return 499;
  if (lower.includes("hd 660s")) return 499;
  if (lower.includes("gsp 600")) return 299;
  if (lower.includes("game zero")) return 199;
  if (lower.includes("game one")) return 259;
  if (lower.includes("quantum one")) return 299;

  // Mid-range
  if (lower.includes("cloud ii")) return 99;
  if (lower.includes("cloud iii")) return 149;
  if (lower.includes("cloud alpha")) return 129;
  if (lower.includes("pro x")) return 139;
  if (lower.includes("pro headset")) return 99;
  if (lower.includes("blackshark")) return 159;
  if (lower.includes("arctis")) return 149;
  if (lower.includes("hs80")) return 179;
  if (lower.includes("hs70")) return 129;
  if (lower.includes("void")) return 99;
  if (lower.includes("quantum")) return 119;

  // Budget/Standard
  if (lower.includes("dt 770")) return 199;
  if (lower.includes("mmx 300")) return 249;
  if (lower.includes("pelta")) return 119;
  if (lower.includes("flight")) return 159;

  // Defaults by brand
  switch (brand) {
    case "Razer": return 149;
    case "HyperX": return 119;
    case "Logitech": return 129;
    case "SteelSeries": return 149;
    case "Corsair": return 129;
    case "Sony": return 199;
    case "Sennheiser": return 299;
    case "beyerdynamic": return 349;
    case "Astro": return 249;
    default: return 99;
  }
}

// ============================================================================
// HELPER: GENERATE RATING
// ============================================================================
function generateRating(userCount) {
  // More popular = higher base rating
  const baseRating = Math.min(9.8, 7.0 + (userCount / 300) * 2.5);
  // Add some pseudo-randomness based on name hash
  return Math.round(baseRating * 10) / 10;
}

