// ============================================================================
// BUILD HEADPHONES ARRAY
// ============================================================================
export const headphones = HEADPHONE_SPECS.map((spec, idx) => {
  const brand = getBrand(spec.name);
  const type = getType(spec.name);
  const style = getStyle(spec.name);
  const price = estimatePrice(spec.name, brand);
  const rating = generateRating(spec.count);

  return {
    id: spec.name.toLowerCase().replace(/\s+/g, "-").replace(/[^\w\-]/g, ""),
    name: spec.name,
    brand,
    type,
    style,
    proUsage: Math.round((spec.count / 1863) * 1000) / 10, // 1863 total players
    userCount: spec.count,
    price,
    rating,
    amazonUrl: spec.url || amazonLink(spec.name),
    imageUrl: `https://m.media-amazon.com/images/I/amazon-product-${idx + 1}._AC_SL1500_.jpg`,
    description: getHeadphoneDescription(spec.name, brand),
  };
});

function getHeadphoneDescription(name, brand) {
  const lower = name.toLowerCase();

  if (lower.includes("cloud ii")) return "Industry-standard gaming headset with excellent sound quality and comfort for long sessions.";
  if (lower.includes("blackshark v2 pro")) return "Premium gaming headset with 7.1 surround and noise-canceling boom mic.";
  if (lower.includes("g pro x")) return "Tournament-grade esports headset trusted by pro players worldwide.";
  if (lower.includes("blackshark v3")) return "Next-gen gaming audio with Razer Hypersense haptics for immersive gameplay.";
  if (lower.includes("cloud iii")) return "Latest HyperX gaming headset with improved comfort and dual connectivity.";
  if (lower.includes("nova pro")) return "Premium wireless esports headset with ChatMix dial and personalized sound.";
  if (lower.includes("arctis")) return "SteelSeries' premium gaming audio with ClearCast microphone and bidirectional 2-way EQ.";
  if (lower.includes("quantum")) return "JBL's gaming headset featuring IMAX Enhanced audio and comfortable memory foam.";
  if (lower.includes("dt 990")) return "Professional studio headphones with open-back design, excellent for critical listening.";
  if (lower.includes("dt 1990")) return "Studio-grade reference headphones with exceptional clarity and frequency response.";
  if (lower.includes("inzone")) return "Sony's dedicated gaming headset with 360 Reality Audio and noise-canceling microphone.";
  if (lower.includes("a50")) return "Premium wireless gaming headset by ASTRO with dolby digital sound.";
  if (lower.includes("game zero")) return "Sennheiser's professional gaming headset with closed-back design.";
  if (lower.includes("void")) return "Corsair's lightweight gaming headset with premium memory foam earcups.";

  return `High-quality ${brand} gaming headset designed for competitive esports performance.`;
}

