// ============================================================================
// BRAND MARKET SHARE (computed from headphones data)
// ============================================================================
export const brandMarketShare = (() => {
  const brandCounts = {};
  headphones.forEach(hp => {
    brandCounts[hp.brand] = (brandCounts[hp.brand] || 0) + hp.userCount;
  });

  return Object.entries(brandCounts)
    .map(([name, count]) => ({
      name,
      value: count,
      color: BRAND_COLORS[name] || "#666666",
    }))
    .sort((a, b) => b.value - a.value);
})();

